import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'When clicking Run' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Edit Fields',
    parameters: {
      mode: 'manual',
      assignments: {
        assignments: []
      }
    }
  }
});

export default workflow('manual-trigger-demo', 'Manual Trigger Demo')
  .add(manualTrigger)
  .to(setNode);
